def _make_callable(self, f):
    """Wrap a UserFunction so it can be called by Python builtins like map/filter."""
    if isinstance(f, UserFunction):
        def call(*args):
            call_env = Environment(parent=f.closure_env)
            for param, arg in zip(f.params, args):
                call_env.set(param, arg)
            try:
                self._eval_body(f.body, call_env)
                return None
            except ReturnSignal as ret:
                return ret.value
        return call
    return f

